// Симуляция чтения ОВЕН ДКВ-С по Modbus RTU (адрес 0x01)
// В реальном проекте заменить на узел node-red-contrib-modbus
// Регистры: 0x0000=CO2(ppm), 0x0001=T(*0.1°C), 0x0002=RH(*0.1%)

// Для тестирования — генерируем реалистичные данные
const hour = new Date().getHours();
let base_co2 = 450;

// Имитация: в часы сеансов CO2 растёт
if (hour >= 12 && hour <= 22) {
    const sessions = [{s:12,e:14},{s:15,e:18},{s:19,e:22}];
    for (const sess of sessions) {
        if (hour >= sess.s && hour <= sess.e) {
            base_co2 = 700 + Math.random() * 400; // 700-1100 ppm
            break;
        }
    }
}

msg.sensor_id = 1;
msg.co2_1 = Math.round(base_co2 + (Math.random() - 0.5) * 40);
msg.temp_1 = 20.5 + (Math.random() - 0.5) * 1.0;
msg.rh_1 = 45 + (Math.random() - 0.5) * 5;
return msg;

// Симуляция чтения ОВЕН ДКВ-С по Modbus RTU (адрес 0x02)
const hour = new Date().getHours();
let base_co2 = 430;

if (hour >= 12 && hour <= 22) {
    const sessions = [{s:12,e:14},{s:15,e:18},{s:19,e:22}];
    for (const sess of sessions) {
        if (hour >= sess.s && hour <= sess.e) {
            base_co2 = 650 + Math.random() * 350;
            break;
        }
    }
}

msg.sensor_id = 2;
msg.co2_2 = Math.round(base_co2 + (Math.random() - 0.5) * 40);
msg.temp_2 = 21.0 + (Math.random() - 0.5) * 0.8;
msg.rh_2 = 47 + (Math.random() - 0.5) * 5;
return msg;

// Объединяем данные двух датчиков и берём максимум CO2
const s1 = msg.payload[1] || {};
const s2 = msg.payload[2] || {};

const co2_1 = s1.co2_1 || 450;
const co2_2 = s2.co2_2 || 450;

// Управляем по максимальному значению (консервативная стратегия)
const co2_max = Math.max(co2_1, co2_2);

// Средняя температура и влажность
const temp = ((s1.temp_1 || 20) + (s2.temp_2 || 20)) / 2;
const rh   = ((s1.rh_1 || 45)   + (s2.rh_2 || 45))   / 2;

// Определяем текущий режим по расписанию
const hour = new Date().getHours();
let mode = 'NIGHT';
if (hour >= 11 && hour <= 23) {
    const sessions = [{s:12,e:14},{s:15,e:18},{s:19,e:22}];
    const prestart = [{s:11,e:12},{s:14,e:15},{s:18,e:19}];
    const interms  = [{s:14,e:15},{s:18,e:19},{s:22,e:23}];
    for (const p of prestart) {
        if (hour >= p.s && hour < p.e) { mode = 'PRESTART'; break; }
    }
    if (mode === 'NIGHT') {
        for (const sess of sessions) {
            if (hour >= sess.s && hour <= sess.e) { mode = 'SESSION'; break; }
        }
    }
    if (mode === 'NIGHT') {
        for (const i of interms) {
            if (hour >= i.s && hour < i.e) { mode = 'INTERMISSION'; break; }
        }
    }
    if (mode === 'NIGHT' && hour >= 11) mode = 'SESSION'; // fallback
}

msg.payload = {
    co2_1: co2_1,
    co2_2: co2_2,
    co2:   co2_max,
    temp:  Math.round(temp * 10) / 10,
    rh:    Math.round(rh * 10) / 10,
    mode:  mode
};
return msg;

// ============================================================
// DCV Controller — алгоритм управления вентиляцией по CO2
// ВКР: Повышение энергоэффективности кинозала, 2025
// ============================================================

const co2  = msg.payload.co2;
const mode = msg.payload.mode || 'SESSION';

// --- Уставки (ppm) ---
const CO2_BG    = 500;   // фоновый уровень (пустой зал)
const CO2_SET   = 1000;  // нормативная уставка (ГОСТ 30494-2011: ≤1400)
const CO2_WARN  = 1200;  // предупредительный порог
const CO2_ALARM = 1400;  // аварийный порог + 100% вентиляция

// --- Пределы производительности вентиляторов (%) ---
const FAN_NIGHT  = 10;   // ночной режим: 10% = 405 м3/ч
const FAN_MIN    = 30;   // дежурная вентиляция: 30% = 1215 м3/ч
const FAN_INTERM = 40;   // межсеансовый: 40% = 1620 м3/ч
const FAN_NOM    = 100;  // номинал: 100% = 4050 м3/ч

// --- Номинальные параметры установки ---
const Q_NOM_M3H  = 4050;  // номинальный расход, м3/ч
const P_NOM_KW   = 1.97;  // номинальная мощность двигателя, кВт

let freq_pct = FAN_MIN;
let alarm = 0;
let warning = 0;
let status_text = '';

// --- Алгоритм управления по режимам ---
switch (mode) {
    case 'NIGHT':
        freq_pct = FAN_NIGHT;
        status_text = '🌙 Ночной режим';
        break;

    case 'PRESTART':
        freq_pct = FAN_NOM;
        status_text = '⚡ Предпуск (прогрев зала)';
        break;

    case 'INTERMISSION':
        freq_pct = FAN_INTERM;
        status_text = '⏸ Межсеансовый перерыв';
        break;

    case 'SESSION':
    default:
        if (co2 >= CO2_ALARM) {
            freq_pct = FAN_NOM;
            alarm = 1;
            warning = 1;
            status_text = '🚨 АВАРИЯ: CO2 > ' + CO2_ALARM + ' ppm!';
        } else if (co2 >= CO2_WARN) {
            freq_pct = FAN_NOM;
            warning = 1;
            status_text = '⚠️ Предупреждение: CO2 > ' + CO2_WARN + ' ppm';
        } else if (co2 <= CO2_BG) {
            freq_pct = FAN_MIN;
            status_text = '✅ Дежурный режим (малая нагрузка)';
        } else {
            // Пропорциональное управление: CO2_BG..CO2_SET → FAN_MIN..FAN_NOM
            freq_pct = FAN_MIN + (FAN_NOM - FAN_MIN) *
                       (co2 - CO2_BG) / (CO2_SET - CO2_BG);
            freq_pct = Math.round(Math.min(FAN_NOM, Math.max(FAN_MIN, freq_pct)));
            status_text = '✅ Активное DCV-управление';
        }
        break;
}

// --- Расчёт выходных параметров ---
const freq_hz   = Math.round(50 * freq_pct / 100);          // Гц
const flow_m3h  = Math.round(Q_NOM_M3H * freq_pct / 100);  // м3/ч
const p_kw      = P_NOM_KW * Math.pow(freq_pct / 100, 3);  // кВт (закон вентилятора)
const p_base_kw = P_NOM_KW;                                  // базовая мощность
const savings_w = Math.round((p_base_kw - p_kw) * 1000);    // экономия, Вт

// --- Формирование выходного сообщения ---
msg.payload = {
    // Входные данные
    co2:        co2,
    co2_1:      msg.payload.co2_1,
    co2_2:      msg.payload.co2_2,
    temp:       msg.payload.temp,
    rh:         msg.payload.rh,
    mode:       mode,
    // Управляющие выходы
    freq_pct:   freq_pct,
    freq_hz:    freq_hz,
    flow_m3h:   flow_m3h,
    // Энергетика
    power_kw:   Math.round(p_kw * 1000) / 1000,
    power_base: p_base_kw,
    savings_w:  savings_w,
    savings_pct: Math.round((1 - Math.pow(freq_pct / 100, 3)) * 100),
    // Сигнализация
    warning:    warning,
    alarm:      alarm,
    status:     status_text,
    // Метка времени
    ts:         new Date().toISOString()
};

// Несколько выходов: 0=норма, 1=предупреждение/авария
const out_idx = alarm ? 1 : 0;
const outputs = [null, null];
outputs[out_idx] = msg;
return outputs;

// Запись уставки частоты в ЧП приточного вентилятора
// Modbus TCP: host=192.168.1.10, port=502, unit=3, register=0x0001
// Значение: 0-1000 = 0-100% (масштаб ЧП ОВЕН ПЧВ3)

const freq_raw = Math.round(msg.payload.freq_pct * 10); // 0-1000

node.send({
    payload: {
        value: freq_raw,
        register: 1,
        unitid: 3,
        fc: 6  // Write Single Register
    },
    info: {
        device: 'VFD_SUPPLY',
        freq_pct: msg.payload.freq_pct,
        freq_hz: msg.payload.freq_hz,
        flow_m3h: msg.payload.flow_m3h
    }
});
return null;

// Запись уставки частоты в ЧП вытяжного вентилятора
// Modbus TCP: host=192.168.1.11, port=502, unit=4, register=0x0001
// Поддерживаем баланс приток=вытяжка

const freq_raw = Math.round(msg.payload.freq_pct * 10); // 0-1000

node.send({
    payload: {
        value: freq_raw,
        register: 1,
        unitid: 4,
        fc: 6
    },
    info: {
        device: 'VFD_EXHAUST',
        freq_pct: msg.payload.freq_pct,
        freq_hz: msg.payload.freq_hz
    }
});
return null;

// Запись данных в CSV-архив с ротацией по суткам
// Файл: /home/node-red/logs/dcv_YYYY-MM-DD.csv

const d = msg.payload;
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const timeStr = now.toTimeString().split(' ')[0];

// CSV-строка: timestamp,co2_1,co2_2,co2_max,temp,rh,mode,freq_pct,flow_m3h,power_kw,savings_pct
const row = [
    `${dateStr} ${timeStr}`,
    d.co2_1, d.co2_2, d.co2,
    d.temp, d.rh,
    d.mode,
    d.freq_pct, d.flow_m3h,
    d.power_kw, d.savings_pct
].join(',');

msg.filename = `/home/node-red/logs/dcv_${dateStr}.csv`;
msg.payload = row + '\n';
msg.flags = { append: true };
return msg;

