// Обработчик аварийных ситуаций
const d = msg.payload;

if (d.alarm) {
    // Аварийная сигнализация: CO2 > 1400 ppm
    node.warn(`АВАРИЯ: CO2=${d.co2} ppm. Вентиляция переведена на 100%.`);

    // Формируем сообщение для уведомления
    msg.topic = 'АВАРИЯ CO2 - Кинозал';
    msg.payload = {
        type: 'ALARM',
        message: `ПРЕВЫШЕНА НОРМА CO2: ${d.co2} ppm (норма ≤ 1400 ppm по ГОСТ 30494-2011)\n` +
                 `Время: ${d.ts}\nВентиляция: 100% (${d.flow_m3h} м3/ч)\n` +
                 `Объект: Кинозал, Ярославский пр. 55`,
        co2: d.co2,
        ts:  d.ts
    };
} else if (d.warning) {
    // Предупредительная сигнализация: CO2 > 1200 ppm
    msg.topic = 'Предупреждение CO2 - Кинозал';
    msg.payload = {
        type: 'WARNING',
        message: `Концентрация CO2 = ${d.co2} ppm (предупредительный уровень 1200 ppm)`,
        co2: d.co2,
        ts:  d.ts
    };
}

return msg;

// Сохраняем выбранный ручной режим в глобальный контекст
if (msg.payload === 'AUTO') {
    global.set('manual_mode', null);
    msg.payload = 'Режим: АВТО (по расписанию)';
} else {
    global.set('manual_mode', msg.payload);
    msg.payload = `Режим принудительно: ${msg.payload}`;
}
return msg;

// Накопительный расчёт суточной экономии
// Вызывается каждые 30 секунд

const d = msg.payload;
const dt_h = 30 / 3600;  // интервал в часах

// Текущая экономия за интервал (кВт·ч)
const delta_e = (d.power_base - d.power_kw) * dt_h;

// Накопление за сутки
let daily_savings = context.get('daily_savings') || 0;
daily_savings += delta_e;
context.set('daily_savings', daily_savings);

// Сброс в полночь
const now = new Date();
if (now.getHours() === 0 && now.getMinutes() < 1) {
    context.set('daily_savings', 0);
}

msg.payload = {
    daily_savings_kwh:  Math.round(daily_savings * 100) / 100,
    daily_savings_rub:  Math.round(daily_savings * 8.64 * 100) / 100,
    current_power_kw:   d.power_kw,
    savings_pct:        d.savings_pct
};
return msg;
